const returnRate = $fromAI('return_rate', 'Product return rate percentage', 'number', 0);
const complaintCount = $fromAI('complaint_count', 'Number of customer complaints', 'number', 0);
const violationHistory = $fromAI('violation_history', 'Number of previous violations', 'number', 0);
const responseTime = $fromAI('avg_response_time', 'Average customer service response time in hours', 'number', 24);

// Scoring algorithm
let score = 0;
score += Math.min(returnRate * 2, 40); // Max 40 points for returns
score += Math.min(complaintCount * 5, 30); // Max 30 points for complaints
score += Math.min(violationHistory * 10, 20); // Max 20 points for history
score += Math.min((responseTime / 24) * 10, 10); // Max 10 points for slow response

// Classify severity
let severity;
if (score < 25) severity = 'low';
else if (score < 50) severity = 'medium';
else if (score < 75) severity = 'high';
else severity = 'critical';

return { score: Math.round(score), severity, breakdown: { returnRate, complaintCount, violationHistory, responseTime } };

